import React, { useState } from "react";
import HomeScreen from "./screens/HomeScreen";
import GoalsScreen from "./screens/GoalsScreen";
import LoansScreen from "./screens/LoansScreen";
import ProfileScreen from "./screens/ProfileScreen";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawalScreen from "./screens/WithdrawalScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawalScreen from "./screens/SavingsWithdrawalScreen";

// Bottom Navigation component
function BottomNav({ current, setCurrent }) {
  const tabs = ["Home", "Goals", "Loans", "Profile"];
  return (
    <div className="fixed bottom-0 left-0 w-full bg-white shadow-inner flex justify-around py-3">
      {tabs.map((tab) => (
        <button
          key={tab}
          onClick={() => setCurrent(tab)}
          className={`font-medium ${current === tab ? "text-teal-600" : "text-gray-400"}`}
        >
          {tab}
        </button>
      ))}
    </div>
  );
}

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Home");
  const [modal, setModal] = useState(null);

  // Mock data
  const [balance, setBalance] = useState(1500);
  const [userName, setUserName] = useState("Faith");
  const [transactions, setTransactions] = useState([
    { id: 1, title: "Salary", type: "deposit", amount: 1200, date: "Jan 20" },
    { id: 2, title: "Groceries", type: "withdrawal", amount: 200, date: "Jan 21" },
    { id: 3, title: "Savings Deposit", type: "deposit", amount: 300, date: "Jan 22" },
  ]);

  // Transaction handlers
  const addTransaction = (title, type, amount) => {
    const newTx = {
      id: transactions.length + 1,
      title,
      type,
      amount: parseFloat(amount),
      date: new Date().toLocaleDateString("en-US", { month: "short", day: "numeric" }),
    };
    setTransactions([newTx, ...transactions]);
  };

  const handleDeposit = (amount) => {
    setBalance(balance + parseFloat(amount));
    addTransaction("App Deposit", "deposit", amount);
    setModal(null);
  };

  const handleWithdrawal = (amount) => {
    setBalance(balance - parseFloat(amount));
    addTransaction("App Withdrawal", "withdrawal", amount);
    setModal(null);
  };

  const handleSavingsDeposit = (goal, amount) => {
    setBalance(balance - parseFloat(amount));
    addTransaction(`Savings: ${goal}`, "deposit", amount);
    setModal(null);
  };

  const handleSavingsWithdrawal = (goal, amount) => {
    setBalance(balance + parseFloat(amount));
    addTransaction(`Withdraw from ${goal}`, "withdrawal", amount);
    setModal(null);
  };

  // Decide which screen to show
  let ScreenComponent;
  switch (currentScreen) {
    case "Home":
      ScreenComponent = <HomeScreen balance={balance} transactions={transactions} setModal={setModal} userName={userName} />;
      break;
    case "Goals":
      ScreenComponent = <GoalsScreen />;
      break;
    case "Loans":
      ScreenComponent = <LoansScreen />;
      break;
    case "Profile":
      ScreenComponent = <ProfileScreen />;
      break;
    default:
      ScreenComponent = <HomeScreen />;
  }

  return (
    <div className="relative min-h-screen bg-gray-50 pb-20">
      {ScreenComponent}

      {/* Modal system */}
      {modal === "deposit" && <DepositScreen onDeposit={handleDeposit} />}
      {modal === "withdraw" && <WithdrawalScreen onWithdraw={handleWithdrawal} />}
      {modal === "savingsDeposit" && <SavingsDepositScreen onDepositToGoal={handleSavingsDeposit} />}
      {modal === "savingsWithdraw" && <SavingsWithdrawalScreen onWithdrawFromGoal={handleSavingsWithdrawal} />}

      {/* Bottom navigation */}
      <BottomNav current={currentScreen} setCurrent={setCurrentScreen} />
    </div>
  );
}
